   143→        // Move rook
   144→        if (isKingSide) {
   145→            this.board.movePiece({ row, col: 7 }, { row, col: 5 });
   146→        } else {
   147→            this.board.movePiece({ row, col: 0 }, { row, col: 3 });
   148→        }
   149→    }
   150→
   151→    /**
   152→     * Execute en passant capture
   153→     * @param {Object} from - Pawn position
   154→     * @param {Object} to - Destination position
   155→     * @returns {Piece} Captured pawn
   156→     */
