   212→        }
   213→    }
   214→
   215→    /**
   216→     * Update game state (check, checkmate, stalemate)
   217→     */
   218→    updateGameState() {
   219→        this.gameState = Rules.getGameState(this.board, this.currentTurn);
   220→    }
   221→
   222→    /**
   223→     * Record move in history
   224→     * @param {Object} from - Source position
   225→     * @param {Object} to - Destination position
   226→     * @param {Piece} piece - Piece moved
   227→     * @param {Piece} captured - Captured piece
   228→     * @param {string} moveType - Type of move
   229→     */
   230→    recordMove(from, to, piece, captured, moveType) {
   231→        const fromNotation = Position.toAlgebraic(from.row, from.col);
   232→        const toNotation = Position.toAlgebraic(to.row, to.col);
   233→
   234→        let moveNotation = '';
   235→
   236→        // Piece symbol
   237→        if (piece.type !== PieceType.PAWN) {
   238→            const symbols = {
   239→                king: 'K', queen: 'Q', rook: 'R', bishop: 'B', knight: 'N'
   240→            };
   241→            moveNotation += symbols[piece.type];
   242→        }
   243→
   244→        // Capture
   245→        if (captured || moveType === 'enpassant') {
   246→            if (piece.type === PieceType.PAWN) {
   247→                moveNotation += fromNotation[0]; // File
   248→            }
   249→            moveNotation += 'x';
   250→        }
   251→
   252→        // Destination
   253→        moveNotation += toNotation;
   254→
   255→        // Special moves notation
   256→        if (moveType === 'castling') {
   257→            moveNotation = to.col > from.col ? 'O-O' : 'O-O-O';
   258→        }
   259→
   260→        // Check/checkmate
   261→        if (this.gameState.status === 'checkmate') {
   262→            moveNotation += '#';
   263→        } else if (this.gameState.inCheck) {
   264→            moveNotation += '+';
   265→        }
   266→
   267→        this.moveHistory.push({
   268→            notation: moveNotation,
   269→            from: fromNotation,
   270→            to: toNotation,
   271→            piece: piece.type,
   272→            color: piece.color,
   273→            capturedPiece: captured, // Store the actual Piece object
   274→            moveType: moveType
   275→        });
   276→    }
   277→
   278→    /**
   279→     * Undo last move
   280→     * @returns {boolean} True if move was undone
   281→     */
   282→    undoMove() {
   283→        if (this.moveHistory.length === 0) {
   284→            return false;
   285→        }
   286→
   287→        const lastMove = this.moveHistory.pop();
   288→
   289→        // Parse positions
   290→        const from = Position.fromAlgebraic(lastMove.from);
   291→        const to = Position.fromAlgebraic(lastMove.to);
   292→
   293→        // Get the piece that moved
   294→        const piece = this.board.getPieceAt(to.row, to.col);
   295→
   296→        // Handle special moves
   297→        if (lastMove.moveType === 'castling') {
   298→            this.undoCastling(from, to);
   299→        } else if (lastMove.moveType === 'enpassant') {
   300→            this.undoEnPassant(from, to);
   301→        } else if (lastMove.moveType === 'promotion') {
   302→            this.undoPromotion(from, to, lastMove.piece);
   303→        } else {
   304→            // Normal move: move piece back
   305→            this.board.movePiece(to, from);
   306→            piece.hasMoved = false; // Reset hasMoved for proper undo
   307→        }
   308→
   309→        // Restore captured piece if there was one
   310→        if (lastMove.capturedPiece && lastMove.moveType !== 'enpassant') {
   311→            this.board.setPieceAt(to.row, to.col, lastMove.capturedPiece);
   312→
   313→            // Remove from captured pieces array
   314→            const capturedColor = lastMove.capturedPiece.color;
   315→            const capturedArray = this.capturedPieces[capturedColor];
   316→            const index = capturedArray.findIndex(p => p.type === lastMove.capturedPiece.type);
   317→            if (index > -1) {
   318→                capturedArray.splice(index, 1);
   319→            }
   320→        }
   321→
   322→        // Switch turns back
   323→        this.switchTurn();
   324→
   325→        // Update game state
   326→        this.updateGameState();
   327→
   328→        // Notify listeners
   329→        this.notifyStateChange();
   330→
   331→        return true;
   332→    }
   333→
   334→    /**
   335→     * Undo castling move
   336→     */
   337→    undoCastling(from, to) {
   338→        const isKingSide = to.col > from.col;
   339→        const row = from.row;
   340→
   341→        // Move king back
   342→        const king = this.board.getPieceAt(to.row, to.col);
   343→        this.board.setPieceAt(from.row, from.col, king);
   344→        king.hasMoved = false;
   345→
   346→        // Move rook back
   347→        if (isKingSide) {
   348→            // Kingside: rook at file F (col 5) moves back to H (col 7)
   349→            const rook = this.board.getPieceAt(row, 5);
   350→            this.board.setPieceAt(row, 7, rook);
   351→            rook.hasMoved = false;
   352→        } else {
   353→            // Queenside: rook at file D (col 3) moves back to A (col 0)
   354→            const rook = this.board.getPieceAt(row, 3);
   355→            this.board.setPieceAt(row, 0, rook);
   356→            rook.hasMoved = false;
   357→        }
   358→    }
   359→
   360→    /**
   361→     * Undo en passant capture
   362→     */
   363→    undoEnPassant(from, to) {
   364→        // Move pawn back
   365→        const pawn = this.board.getPieceAt(to.row, to.col);
   366→        this.board.setPieceAt(from.row, from.col, pawn);
   367→        pawn.hasMoved = false;
   368→
   369→        // Restore captured pawn (it's on a different square than the 'to' position)
   370→        const capturedRow = from.row; // The captured pawn was on the same row as where the moving pawn started
   371→        const capturedPiece = this.moveHistory[this.moveHistory.length]?.capturedPiece;
   372→
   373→        // Find the captured pawn from the last move's data
   374→        const lastMoveData = this.moveHistory.length > 0 ?
   375→            this.moveHistory[this.moveHistory.length] : null;
   376→
   377→        if (lastMoveData && lastMoveData.capturedPiece) {
   378→            this.board.setPieceAt(capturedRow, to.col, lastMoveData.capturedPiece);
   379→
   380→            // Remove from captured pieces
   381→            const capturedColor = lastMoveData.capturedPiece.color;
   382→            const capturedArray = this.capturedPieces[capturedColor];
   383→            const index = capturedArray.findIndex(p => p.type === lastMoveData.capturedPiece.type);
   384→            if (index > -1) {
   385→                capturedArray.splice(index, 1);
   386→            }
   387→        }
   388→    }
   389→
   390→    /**
   391→     * Undo pawn promotion
   392→     */
   393→    undoPromotion(from, to, originalType) {
   394→        // Demote back to pawn
   395→        const { createPiece } = require('./pieces.js');
   396→        const pawn = createPiece(this.currentTurn, PieceType.PAWN, from.row, from.col);
   397→        this.board.setPieceAt(from.row, from.col, pawn);
   398→
   399→        // Clear the promoted piece's square
   400→        this.board.setPieceAt(to.row, to.col, null);
   401→    }
   402→
   403→    /**
   404→     * Get valid moves for a piece
   405→     * @param {Object} pos - Position {row, col}
   406→     * @returns {Array} Array of valid moves
   407→     */
   408→    getValidMoves(pos) {
   409→        return Rules.getLegalMoves(this.board, pos);
   410→    }
   411→
   412→    /**
   413→     * Notify state change listeners
   414→     */
   415→    notifyStateChange() {
   416→        if (this.onStateChange) {
   417→            this.onStateChange({
   418→                currentTurn: this.currentTurn,
   419→                gameState: this.gameState,
   420→                moveHistory: this.moveHistory,
   421→                capturedPieces: this.capturedPieces
   422→            });
   423→        }
   424→    }
   425→
   426→    /**
   427→     * Export game state
   428→     * @returns {Object} Game state
   429→     */
   430→    exportState() {
   431→        return {
   432→            board: this.board.getState(),
   433→            currentTurn: this.currentTurn,
   434→            gameState: this.gameState,
   435→            moveHistory: this.moveHistory,
   436→            capturedPieces: this.capturedPieces.map(p => ({
   437→                color: p.color,
   438→                type: p.type
   439→            }))
   440→        };
   441→    }
   442→
   443→    /**
   444→     * Import game state
   445→     * @param {Object} state - Game state to import
   446→     */
   447→    importState(state) {
   448→        // Implementation for loading saved games
   449→        // This would reconstruct the board from state
   450→    }
   451→
   452→    /**
   453→     * Reset the game
   454→     */
   455→    reset() {
   456→        this.init();
   457→    }
   458→}
