/**
 * Chess rules validation
 * Handles check, checkmate, special moves, and move validation
 */

class Rules {
    /**
     * Validate a move and return if it's legal
     * @param {Board} board - The game board
     * @param {Object} from - Source position
     * @param {Object} to - Destination position
     * @param {string} color - Color of player making move
     * @returns {Object} Validation result {valid, reason, moveType}
     */
    static validateMove(board, from, to, color) {
        const piece = board.getPieceAt(from.row, from.col);

        // Check if there's a piece at source
        if (!piece) {
            return { valid: false, reason: 'No piece at source position' };
        }

        // Check if piece belongs to current player
        if (piece.color !== color) {
            return { valid: false, reason: 'Not your piece' };
        }

        // Get all valid moves for this piece
        const validMoves = piece.getValidMoves(board);

        // Check if destination is in valid moves
        const isValidDestination = validMoves.some(move =>
            move.row === to.row && move.col === to.col
        );

        if (!isValidDestination) {
            return { valid: false, reason: 'Invalid move for this piece' };
        }

        // Check if move would leave king in check
        const clonedBoard = board.clone();
        clonedBoard.movePiece(from, to);

        // Handle en passant capture
        if (to.isEnPassant) {
            const captureRow = from.row;
            const captureCol = to.col;
            clonedBoard.setPieceAt(captureRow, captureCol, null);
        }

        const kingPos = clonedBoard.findKing(color);
        if (!kingPos) {
            return { valid: false, reason: 'King not found' };
        }

        const enemyColor = color === PieceColor.WHITE ? PieceColor.BLACK : PieceColor.WHITE;
        if (clonedBoard.isPositionUnderAttack(kingPos, enemyColor)) {
            return { valid: false, reason: 'Would leave king in check' };
        }

        // Determine move type
        let moveType = 'normal';

        // Check for castling
        if (piece.type === PieceType.KING && Math.abs(to.col - from.col) === 2) {
            moveType = 'castling';
        }

        // Check for en passant
        if (to.isEnPassant) {
            moveType = 'enpassant';
        }

        // Check for pawn promotion
        if (piece.type === PieceType.PAWN) {
            if ((color === PieceColor.WHITE && to.row === 0) ||
                (color === PieceColor.BLACK && to.row === 7)) {
                moveType = 'promotion';
            }
        }

        return { valid: true, moveType };
    }

    /**
     * Check if a king is in check
     * @param {Board} board - The game board
     * @param {string} color - Color of king to check
     * @returns {boolean} True if king is in check
     */
    static isCheck(board, color) {
        const kingPos = board.findKing(color);
        if (!kingPos) {
            return false;
        }

        const enemyColor = color === PieceColor.WHITE ? PieceColor.BLACK : PieceColor.WHITE;
        return board.isPositionUnderAttack(kingPos, enemyColor);
    }

