     1→/**
     2→ * Canvas renderer for the chess board
     3→ * Handles all drawing operations for the game
     4→ */
     5→
     6→class Renderer {
     7→    constructor(canvas, board) {
     8→        this.canvas = canvas;
     9→        this.ctx = canvas.getContext('2d');
    10→        this.board = board;
    11→        this.squareSize = canvas.width / 8;
    12→        this.selectedSquare = null;
    13→        this.validMoves = [];
    14→        this.lastMove = null;
    15→        this.animationManager = new AnimationManager();
    16→        this.checkAnimation = null;
    17→        this.gameOverAnimation = null;
    18→        this.hoveredSquare = null;
    19→    }
    20→
    21→    /**
    22→     * Render the entire board
    23→     */
    24→    render() {
    25→        this.clearCanvas();
    26→        this.drawBoard();
    27→        this.drawHighlights();
    28→        this.drawPieces();
    29→        this.drawAnimations();
    30→        this.drawDecorations();
    31→    }
    32→
    33→    /**
    34→     * Clear the canvas
    35→     */
    36→    clearCanvas() {
    37→        this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    38→    }
    39→
    40→    /**
    41→     * Draw the board squares
    42→     */
    43→    drawBoard() {
    44→        for (let row = 0; row < 8; row++) {
    45→            for (let col = 0; col < 8; col++) {
    46→                const x = col * this.squareSize;
    47→                const y = row * this.squareSize;
    48→                const isDark = (row + col) % 2 === 1;
    49→
    50→                if (isDark) {
    51→                    GoTTheme.patterns.darkSquare(this.ctx, x, y, this.squareSize);
    52→                } else {
    53→                    GoTTheme.patterns.lightSquare(this.ctx, x, y, this.squareSize);
    54→                }
    55→            }
    56→        }
    57→    }
    58→
    59→    /**
    60→     * Draw highlights (selected, valid moves, check, etc.)
    61→     */
    62→    drawHighlights() {
    63→        // Highlight last move
    64→        if (this.lastMove) {
    65→            GoTTheme.drawHighlight(
    66→                this.ctx,
    67→                this.lastMove.from.col * this.squareSize,
    68→                this.lastMove.from.row * this.squareSize,
    69→                this.squareSize,
    70→                'lastMove'
    71→            );
    72→            GoTTheme.drawHighlight(
    73→                this.ctx,
    74→                this.lastMove.to.col * this.squareSize,
    75→                this.lastMove.to.row * this.squareSize,
    76→                this.squareSize,
    77→                'lastMove'
    78→            );
    79→        }
    80→
    81→        // Highlight selected square
    82→        if (this.selectedSquare) {
    83→            GoTTheme.drawHighlight(
    84→                this.ctx,
    85→                this.selectedSquare.col * this.squareSize,
    86→                this.selectedSquare.row * this.squareSize,
    87→                this.squareSize,
    88→                'selected'
    89→            );
    90→        }
    91→
    92→        // Draw valid move indicators
    93→        for (const move of this.validMoves) {
    94→            const x = move.col * this.squareSize;
    95→            const y = move.row * this.squareSize;
    96→
    97→            const targetPiece = this.board.getPieceAt(move.row, move.col);
    98→            const isCapture = targetPiece !== null || move.isEnPassant;
    99→
   100→            GoTTheme.drawMoveIndicator(this.ctx, x, y, this.squareSize, isCapture);
   101→        }
   102→
   103→        // Highlight king if in check
   104→        const gameState = Rules.getGameState(this.board, this.board.currentTurn || 'white');
   105→        if (gameState.inCheck) {
   106→            const kingPos = this.board.findKing(this.board.currentTurn || 'white');
